Following my baseApi view: 

```python
class BaseApi(mixins.RetrieveModelMixin,
              mixins.ListModelMixin,
              mixins.UpdateModelMixin,
              mixins.DestroyModelMixin,
              BulkCreateModelMixin,
              BulkUpdateModelMixin,
              generics.GenericAPIView):

    filter_backends = (OrderingFilter, SearchFilter, DjangoFilterBackend)
    pagination_class = StandardResultsSetPagination

    # def get_queryset(self):
    #     data = self.request.DATA
    #     queryset = self.queryset
    #     for key in self.request.DATA:
    #         if key.replace('or_', '') in self.or_filter_fields and 'or_' in key:
    #             queryset = queryset.filter(key=data[key])

    #     return queryset

    def get_list(self, request, *args, **kwargs):

        queryset = self.filter_queryset(self.get_queryset())

        page = self.paginate_queryset(queryset)

        if page is not None:
            serializer = self.get_serializer(page, many=True)
            response = self.get_paginated_response(serializer.data)
        else:
            serializer = self.get_serializer(queryset, many=True)
            response = Response(serializer.data)

        query = {
            "ordering_fields": [],
            "filter_fields": [],
            "search_fields": [],
            "element_count": len(response.data),
            "element_total_count": queryset.count(),
            "previous_page": self.paginator.get_previous_link(),
            "next_page": self.paginator.get_next_link(),
            "page_count": self.paginator.page.paginator.num_pages,
            "current_page_size": self.paginator.get_page_size(request),
            "current_page": self.paginator.page.number,
            "max_page_size": self.paginator.max_page_size,
        }

        for backend in list(self.filter_backends):
            if isinstance(backend(), OrderingFilter):
                query["ordering_fields"] = backend().get_ordering(
                    request=self.request,
                    queryset=self.queryset.all(),
                    view=self
                ) or []
            elif isinstance(backend(), SearchFilter):
                query["search_fields"] = backend().get_search_terms(request)
            elif isinstance(backend(), DjangoFilterBackend):
                for f in self.request.query_params.keys():
                    if hasattr(self, 'filter_fields'):
                        if f in self.filter_fields:
                            query["filter_fields"].append({f: self.request.query_params[f]})
                    elif hasattr(self, 'filter_class'):
                        if f in self.filter_class.Meta.fields:
                            query["filter_fields"].append({f: self.request.query_params[f]})

        for k, v in query.items():
            response[k.replace("_", " ").title().replace(" ", "-")] = json.dumps(v)

        if "debug" in self.request.query_params.keys() and self.request.query_params["debug"] == "true":
            response.data = {
                "query": query,
                "data": response.data,
            }

        return response

    # API BASE VIEWS ###########################
    def get(self, request, *args, **kwargs):
        if 'pk' in kwargs.keys():
            return self.retrieve(request, *args, **kwargs)
        else:
            return self.get_list(request, *args, **kwargs)

    def put(self, request, *args, **kwargs):
        if 'pk' in kwargs.keys():
            return self.update(request, partial=True)
        else:
            return self.partial_bulk_update(request, *args, **kwargs)

    def delete(self, request, *args, **kwargs):
        return self.destroy(request, *args, **kwargs)

    def post(self, request, *args, **kwargs):
        return self.create(request, *args, **kwargs)
    # END API BASE VIEWS #######################
```

I'm trying update/create a number of DNS records. I've limited it to creating one for testing purposes, here is the format of the script I'm using:

``` python
#!/usr/bin/env python3

import boto3
import botocore

client = boto3.client('route53')
zone_id = '/hostedzone/ZONEID'

try:
	response = client.change_resource_record_sets(
		HostedZoneId=zone_id,
		ChangeBatch={
			'Changes': [
				{
					'Action': 'UPSERT',
              		'ResourceRecordSet': {
              			'Name': 'www.example.com',
                        'ResourceRecords': [
                        	{
                        		'Value': '10.0.0.1'
                        	}
                        ],
                        'Type': 'A'
                    }
                }
            ]
        }
	)
	print(response)
except botocore.exceptions.ClientError as e:
	print(e)
```

I am certain that I'm using the correct `HostedZoneId` property (the response is the same whether or not I prefix with /hostedzone or not). I am also certain I am using a fully qualified domain for the `Name` property of the `ResourceRecordSet`.

I am using Python 3.5.1 and the latest pip3 install of boto3.

The error produced when running the code above as described is `An error occurred (InvalidInput) when calling the ChangeResourceRecordSets operation: Invalid request`.

I'm not sure how important the cleanup that is to be performed is, but I'm pretty sure it's not happening.

I haven't looked yet, but this is likely happening in other spots as well.

https://github.com/deis/deis/blob/master/router/boot.go#L88

```
func main() {
  // ...
  exitChan := make(chan os.Signal, 2)
  signal.Notify(exitChan, syscall.SIGTERM, syscall.SIGINT)
  go cleanOnExit(exitChan)
  <-exitChan
}
```

The issue is that the main goroutine can potentially exit (and does) before the `cleanOnExit()` function performs cleanup.

Here's a trivial program that demonstrates the techniques does not work.

```
package main

import (
	"fmt"
	"os"
	"os/signal"
	"syscall"
)

func main() {
	exitChan := make(chan os.Signal, 2)
	signal.Notify(exitChan, syscall.SIGTERM, syscall.SIGINT)
	go cleanOnExit(exitChan)
	fmt.Println("Waiting for interrupt...")
	<-exitChan
}

func cleanOnExit(exitChan chan os.Signal) {
	for _ = range exitChan {
		fmt.Println("Cleaning up...")
	}
}
```

